+    const delta = chunk.choices[0].delta;
+    if (delta.content) {
+      fullContent += delta.content;
+      process.stdout.write(delta.content); // stream to terminal
+    }
+  }
+
+  console.log("\n\nFull response:", fullContent);
+}
